import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { getDocs, deleteDoc } from "../../api/documentApi";

export default function DocumentList() {
  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(false);

  const load = async () => {
    try {
      setLoading(true);
      const res = await getDocs();
      setDocs(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load documents");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this document permanently?")) return;

    try {
      await deleteDoc(id);
      setDocs((prev) => prev.filter((d) => d._id !== id));
      alert("Document deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const getVehicleName = (v) => {
    if (!v) return "-";
    return `${v.brand || ""} ${v.type || ""}`.trim() || "-";
  };

  const getVehicleNumber = (v) => {
    if (!v) return "-";
    return v.vehicleNumber || v.vehicle_number || v.registrationNo || v.regNo || "-";
  };

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Physical Documents</h2>

        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={load} style={{ padding: "6px 10px" }}>
            Refresh
          </button>

          <Link to="/documents/add">
            <button style={{ padding: "6px 10px" }}>+ Add Document</button>
          </Link>
        </div>
      </div>

      <div style={{ marginTop: 14 }}>
        {loading && <p>Loading...</p>}

        {!loading && (
          <table border="1" cellPadding="10" style={{ width: "100%", textAlign: "left" }}>
            <thead>
              <tr>
                <th>Type</th>
                <th>Vehicle</th>
                <th>Vehicle Number</th>
                <th>Status</th>
                <th>Location</th>
                <th>Note</th>
                <th style={{ width: 200 }}>Actions</th>
              </tr>
            </thead>

            <tbody>
              {docs.map((d) => (
                <tr key={d._id}>
                  <td>{d.docType || "-"}</td>
                  <td>{getVehicleName(d.vehicle)}</td>
                  <td>{getVehicleNumber(d.vehicle)}</td>
                  <td>{d.status || "-"}</td>
                  <td>{d.location || "-"}</td>
                  <td
                    style={{
                      maxWidth: 260,
                      whiteSpace: "nowrap",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                    }}
                    title={d.notes || ""}
                  >
                    {d.notes || "-"}
                  </td>
                  <td>
                    <Link to={`/documents/edit/${d._id}`}>
                      <button>Edit</button>
                    </Link>

                    <button
                      onClick={() => handleDelete(d._id)}
                      style={{
                        marginLeft: 6,
                        background: "#ef4444",
                        color: "#fff",
                        border: "none",
                        padding: "6px 10px",
                        borderRadius: 4,
                        cursor: "pointer",
                      }}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}

              {docs.length === 0 && (
                <tr>
                  <td colSpan="7">No documents found</td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
